INSERT INTO public.services (id, name, slug, category, is_active, created_at, updated_at, summary, description, price_from, price_unit, treatment_time, results_timeline, results_duration, recovery_time, aliases, hero_rating, hero_review_count, is_published, review_status, faqs) VALUES ('5eff1b8a-9cbe-4d06-beb6-61df499750b4', 'Ultherapy', 'ultherapy', 'Skin', true, '2026-06-24 09:02:19.142227+00', '2026-06-24 13:01:16.228024+00', 'Focused ultrasound that lifts and tightens the skin from deep within, non-surgically.', 'Ultherapy uses micro-focused ultrasound energy to reach the deep foundational layers of the skin, stimulating collagen to lift and tighten the brow, neck, and under-chin. As the only FDA-cleared ultrasound lift, it delivers gradual, natural-looking firming over two to three months with no downtime.', 1500, 'Treatment', '30-90 mins', '2-3 months', '1-2 Years', 'None', '{ultherapy,ulthera,"ultrasound skin tightening","ultrasound therapy","ultrasound lift","micro-focused ultrasound",sofwave,"high intensity focused ultrasound",hifu}', NULL, 0, true, 'approved', '[{"a": "Ultherapy is a non-invasive treatment that uses microfocused ultrasound energy to lift and tighten the skin naturally.", "q": "What is Ultherapy?"}, {"a": "A face and neck procedure typically takes 60-90 minutes, while a chest treatment takes approximately 30 minutes.", "q": "How long does an Ultherapy treatment take?"}, {"a": "Results unfold over 2-3 months and can last up to a year or more, depending on your body''s natural aging process.", "q": "How long do the results last?"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.services (id, name, slug, category, is_active, created_at, updated_at, summary, description, price_from, price_unit, treatment_time, results_timeline, results_duration, recovery_time, aliases, hero_rating, hero_review_count, is_published, review_status, faqs) VALUES ('2a461a03-54fa-4413-8d03-031a3ce121b2', 'HydraFacial', 'hydrafacial', 'Skin', true, '2026-06-24 09:02:19.142227+00', '2026-06-24 10:20:26.940213+00', 'A medical-grade facial that cleanses, exfoliates, extracts, and hydrates in one session.', 'HydraFacial is a multi-step, medical-grade facial that cleanses, gently exfoliates, extracts impurities, and infuses the skin with hydrating serums and antioxidants. It improves tone, clarity, and radiance with no downtime, making it a popular maintenance treatment for nearly every skin type.', 175, 'Session', '30-45 mins', 'Immediately', '2-4 Weeks', 'None', '{hydrafacial,"hydra facial","hydro facial",hydrodermabrasion,facial,facials,"facial treatment","facial treatments","medical facial","medical-grade facial","signature facial","dermaplaning facial"}', 4.50, 2, true, 'approved', '[{"a": "For optimal skin health, we recommend one treatment per month. It''s an excellent maintenance treatment to keep your skin clear and glowing.", "q": "How often should I get a HydraFacial?"}, {"a": "Yes! HydraFacial provides an immediate ''glow'' with absolutely zero downtime, making it the perfect pre-event treatment.", "q": "Can I get a HydraFacial before a big event?"}, {"a": "Yes, the gentle extraction and exfoliation steps help clear congested pores, while the specific serums can be tailored to address acne-prone skin.", "q": "Is HydraFacial good for acne?"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.services (id, name, slug, category, is_active, created_at, updated_at, summary, description, price_from, price_unit, treatment_time, results_timeline, results_duration, recovery_time, aliases, hero_rating, hero_review_count, is_published, review_status, faqs) VALUES ('e450ba93-b5af-46b9-b2b6-efdd41ba871d', 'CoolSculpting', 'coolsculpting', 'Body', true, '2026-06-24 09:02:19.142227+00', '2026-06-24 13:01:15.469891+00', 'Freezes and permanently eliminates stubborn fat without surgery or downtime.', 'CoolSculpting (cryolipolysis) uses controlled cooling to freeze and permanently destroy stubborn fat cells in areas that resist diet and exercise, such as the abdomen, flanks, and under the chin. The body naturally clears the treated cells over the following weeks for a more contoured shape with no surgery or downtime.', 750, 'Treatment', '35-60 mins', '1-3 months', 'Long-term', 'None', '{coolsculpting,"cool sculpting","coolsculpting elite",cryolipolysis,"fat freezing",fat-freezing}', NULL, NULL, true, 'approved', '[{"a": "Each session typically takes about 35 to 60 minutes per treated area, depending on the applicator used.", "q": "How long does a CoolSculpting session take?"}, {"a": "You may start to see changes as quickly as three weeks after your treatment, with the most dramatic results visible after two months.", "q": "When will I see results from CoolSculpting?"}, {"a": "Yes, once the treated fat cells are crystallized (frozen), your body naturally processes and eliminates them. Once gone, they do not return.", "q": "Is the fat loss permanent?"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.services (id, name, slug, category, is_active, created_at, updated_at, summary, description, price_from, price_unit, treatment_time, results_timeline, results_duration, recovery_time, aliases, hero_rating, hero_review_count, is_published, review_status, faqs) VALUES ('1cfe44ca-42ce-4cda-b0cc-26246c53a9d8', 'Kybella', 'kybella', 'Injectables', true, '2026-06-22 14:49:05.613483+00', '2026-06-24 10:20:25.740236+00', 'An injectable that permanently dissolves fat under the chin without surgery.', 'Kybella is an FDA-approved injectable that uses synthetic deoxycholic acid to permanently destroy fat cells beneath the chin. Over a series of sessions it reduces the appearance of a double chin to reveal a more defined, contoured jawline without surgery.', 600, 'Treatment', '20-30 mins', '4-6 weeks', 'Permanent', '3-5 days', '{kybella,"kybella & liquid lipo","kybella and liquid lipo","liquid lipo","deoxycholic acid","fat dissolving injections","submental fat reduction"}', 4.50, 2, true, 'approved', '[{"a": "Most patients need 2 to 4 treatment sessions spaced about 4-6 weeks apart to achieve optimal results.", "q": "How many Kybella treatments will I need?"}, {"a": "Yes, once the fat cells are destroyed by the deoxycholic acid in Kybella, they can no longer store or accumulate fat.", "q": "Is the fat reduction from Kybella permanent?"}, {"a": "Swelling is very common and actually indicates the product is working. Significant swelling typically peaks at 2-3 days and resolves over the following week.", "q": "What should I expect during recovery?"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.services (id, name, slug, category, is_active, created_at, updated_at, summary, description, price_from, price_unit, treatment_time, results_timeline, results_duration, recovery_time, aliases, hero_rating, hero_review_count, is_published, review_status, faqs) VALUES ('14e456e3-aa0c-4057-8d6f-b75ded201cae', 'Body Contouring', 'body-contouring', 'Body', true, '2026-06-24 09:02:19.142227+00', '2026-06-24 13:01:15.991304+00', 'Non-surgical contouring that reduces fat and tones muscle to refine body shape.', 'Body contouring treatments target stubborn fat and lax tissue while toning underlying muscle to refine the contours of the abdomen, flanks, arms, and more. Non-surgical platforms such as EmSculpt and truSculpt reduce fat and build muscle definition with little to no downtime.', 800, 'Session', '30-60 mins', '3-12 weeks', 'Long-term', 'None', '{"body contouring","body sculpting","fat reduction",emsculpt,"emsculpt neo",trusculpt,"trusculpt id",sculpsure,"body fx","muscle toning"}', NULL, 0, true, 'approved', '[{"a": "Ideal candidates are close to their target weight but have stubborn areas of fat or loose skin that haven''t responded to diet and exercise.", "q": "Am I a good candidate for body contouring?"}, {"a": "No, body contouring is designed to sculpt and shape the body by targeting specific areas of fat, not for overall weight loss.", "q": "Is body contouring a weight-loss treatment?"}, {"a": "Results typically develop gradually over 1 to 3 months as the body processes the targeted fat cells and produces new collagen.", "q": "Are the results immediate?"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.services (id, name, slug, category, is_active, created_at, updated_at, summary, description, price_from, price_unit, treatment_time, results_timeline, results_duration, recovery_time, aliases, hero_rating, hero_review_count, is_published, review_status, faqs) VALUES ('5aa3d56e-44c9-47bd-ac2e-7f1fa80f531e', 'Microneedling', 'microneedling', 'Skin', true, '2026-06-22 14:49:05.613483+00', '2026-06-24 10:20:26.610596+00', 'Stimulates collagen with fine micro-channels to refine skin texture, scars, and tone.', 'Microneedling uses fine needles to create controlled micro-channels in the skin, triggering natural collagen and elastin production. RF microneedling platforms such as Morpheus8 and Sylfirm X add radiofrequency heat to remodel deeper tissue. Over a series of sessions it improves texture, fine lines, acne scarring, and overall radiance with little downtime.', 300, 'Session', '45-60 mins', '1-2 weeks', '6-12 Months', '1-3 days', '{microneedling,micro-needling,"micro needling","collagen induction","collagen induction therapy",skinpen,"rf microneedling","radiofrequency microneedling","rf microneedling and microneedling","microneedling / rf microneedling","microneedling/rf microneedling",morpheus8,"morpheus 8","morpheus8 treatment","sylfirm x","sylfirm x rf microneedling",sylfirm,vivace,"secret rf","ruma gold microchannel treatment","ruma gold microchannel","ruma gold"}', 4.50, 2, true, 'approved', '[{"a": "For general rejuvenation, 3 sessions spaced 4-6 weeks apart are typical. For deeper acne scars, 4-6 sessions may be recommended.", "q": "How many microneedling sessions are recommended?"}, {"a": "Your skin will likely look and feel like you have a mild sunburn for 24-48 hours. Most redness subsides by the second day.", "q": "What does my skin look like immediately after?"}, {"a": "Yes, unlike some laser treatments, microneedling does not use heat and is generally safe for all skin types and tones with minimal risk of hyperpigmentation.", "q": "Is microneedling safe for all skin tones?"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.services (id, name, slug, category, is_active, created_at, updated_at, summary, description, price_from, price_unit, treatment_time, results_timeline, results_duration, recovery_time, aliases, hero_rating, hero_review_count, is_published, review_status, faqs) VALUES ('7288006a-eedb-4f76-82d7-d7dbf0e4d0df', 'PRP (Platelet-Rich Plasma)', 'prp-prf', 'Injectables', true, '2026-06-22 14:49:05.613483+00', '2026-06-24 13:01:16.715305+00', 'Uses the body''s own platelets to rejuvenate skin, restore volume, and boost healing.', 'PRP and PRF concentrate the growth factors in your own blood to stimulate collagen, improve skin texture and tone, and support natural healing. Commonly used for facial rejuvenation, under-eye revitalization, and hair restoration with little downtime.', 650, 'Session', '45-60 mins', '3-6 weeks', '6-12 Months', '1-2 days', '{prp,prf,prp/prf,"platelet rich plasma","platelet-rich plasma","platelet rich fibrin","platelet-rich fibrin","regenerative aesthetics (prp/prf)","regenerative aesthetics","vampire facial","vampire facelift","prp facial","prp hair restoration","prp microneedling"}', 4.50, 2, true, 'approved', '[{"a": "Both use your own blood, but PRF (Platelet-Rich Fibrin) is spun at a lower speed, retaining more white blood cells and stem cells for a slower, longer-lasting release of growth factors.", "q": "What is the difference between PRP and PRF?"}, {"a": "They are commonly used for hair restoration, skin rejuvenation (often combined with microneedling), and treating dark under-eye circles.", "q": "What can PRP/PRF treat?"}, {"a": "Most providers recommend a series of 3-4 treatments spaced 4-6 weeks apart for the best results.", "q": "How many treatments will I need?"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.services (id, name, slug, category, is_active, created_at, updated_at, summary, description, price_from, price_unit, treatment_time, results_timeline, results_duration, recovery_time, aliases, hero_rating, hero_review_count, is_published, review_status, faqs) VALUES ('734f962f-5916-4990-b84c-2738ac7532c5', 'Botox', 'botox', 'Injectables', true, '2026-06-22 14:49:05.613483+00', '2026-06-24 10:20:24.491637+00', 'Smooths dynamic wrinkles by relaxing the facial muscles responsible for fine lines.', 'Botox and other neuromodulators are non-surgical injectables that temporarily relax targeted facial muscles to soften the appearance of fine lines and wrinkles. They are most commonly used on forehead lines, frown lines, and crow''s feet while preserving natural, expressive movement.', 12, 'Unit', '20-30 mins', 'Within 1 week', '3-4 Months', 'None', '{botox,tox,neuromodulator,neuromodulators,neurotoxin,botulinum,"botulinum toxin",onabotulinumtoxina,"wrinkle relaxer","anti-wrinkle injections",dysport,abobotulinumtoxina,xeomin,jeuveau,daxxify,newtox}', 4.50, 2, true, 'approved', '[{"a": "You''ll typically start seeing results within 3 to 5 days, with full results visible in 10 to 14 days.", "q": "How long does Botox take to work?"}, {"a": "Most patients experience very minimal discomfort. We use ultra-fine needles, and the injections take just a few minutes.", "q": "Does getting Botox hurt?"}, {"a": "Results generally last 3 to 4 months. With regular treatments, the muscles may become trained to relax, potentially extending the time between sessions.", "q": "How long does Botox last?"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.services (id, name, slug, category, is_active, created_at, updated_at, summary, description, price_from, price_unit, treatment_time, results_timeline, results_duration, recovery_time, aliases, hero_rating, hero_review_count, is_published, review_status, faqs) VALUES ('a1232a0c-ddb8-4cf7-840e-c08b4be7825c', 'Laser Hair Removal', 'laser-hair-removal', 'Laser', true, '2026-06-22 14:49:05.613483+00', '2026-06-24 13:01:16.958735+00', 'Targets hair follicles with light energy for long-lasting, smooth skin.', 'Laser hair removal uses concentrated light energy to target and disable hair follicles, progressively reducing unwanted hair growth. Performed over a series of sessions, it delivers long-lasting smoothness on the face and body with minimal discomfort and no downtime.', 99, 'Session', '15-60 mins', 'After 2-3 sessions', 'Long-term', 'None', '{"laser hair removal",lhr,"laser hair","hair removal","diode laser hair removal"}', NULL, 0, true, 'approved', '[{"a": "It offers long-term hair reduction, significantly decreasing hair growth. Some maintenance treatments may be needed over time.", "q": "Is laser hair removal permanent?"}, {"a": "Hair grows in cycles, so typically 6-8 sessions are needed to target all hair follicles during their active growth phase.", "q": "How many sessions are required?"}, {"a": "Modern lasers are safe for all skin tones, but the treatment is most effective on dark hair. It is generally not effective on blonde, gray, or red hair.", "q": "Does laser hair removal work on all skin and hair colors?"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.services (id, name, slug, category, is_active, created_at, updated_at, summary, description, price_from, price_unit, treatment_time, results_timeline, results_duration, recovery_time, aliases, hero_rating, hero_review_count, is_published, review_status, faqs) VALUES ('1148cf9a-7640-43a4-b49c-96656d09a78e', 'Chemical Peels', 'chemical-peels', 'Skin', true, '2026-06-22 14:49:05.613483+00', '2026-06-24 13:01:17.443974+00', 'Resurfaces dull, damaged skin with exfoliating acid solutions for a fresh glow.', 'Chemical peels use medical-grade acid solutions to exfoliate the outermost layers of skin, revealing smoother, brighter, more even-toned skin underneath. Available from light to deep formulations, they target fine lines, sun damage, acne, and hyperpigmentation with customizable downtime.', 150, 'Treatment', '30-45 mins', '3-7 days', '1-3 Months', '1-7 days', '{"chemical peels","chemical peel",peel,peels,"vi peel","perfect derma peel","jessner peel","tca peel","glycolic peel"}', NULL, 0, true, 'approved', '[{"a": "Not necessarily. Depending on the depth of the peel, you may experience light flaking to sheet peeling. Some superficial peels cause no visible peeling at all.", "q": "Will my skin actually peel off?"}, {"a": "Peels are excellent for treating acne, hyperpigmentation, melasma, fine lines, and uneven skin texture.", "q": "What do chemical peels treat?"}, {"a": "Discontinue retinols, exfoliating acids, and avoid sun exposure for at least 3-5 days before your peel.", "q": "How should I prep for a chemical peel?"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.services (id, name, slug, category, is_active, created_at, updated_at, summary, description, price_from, price_unit, treatment_time, results_timeline, results_duration, recovery_time, aliases, hero_rating, hero_review_count, is_published, review_status, faqs) VALUES ('32cb4064-2b95-45af-9100-742469976364', 'Dermal Fillers', 'dermal-fillers', 'Injectables', true, '2026-06-22 14:49:05.613483+00', '2026-06-24 10:20:24.802656+00', 'Restores lost volume and smooths folds using injectable hyaluronic acid and volumizing gels.', 'Dermal fillers are injectable gels, most often hyaluronic acid based, used to restore lost facial volume, smooth deep folds, and refine the contours of the cheeks, lips, under-eyes, and jawline. Collagen-stimulating options such as Sculptra and Radiesse deliver gradual, longer-lasting volume restoration without surgery.', 650, 'Syringe', '30-45 mins', 'Immediately', '6-18 Months', '1-2 days', '{"dermal fillers","dermal filler",filler,fillers,"lip filler","lip fillers","cheek filler","under eye filler","under-eye filler","tear trough filler","hyaluronic acid",juvederm,restylane,rha,versa,skinvive,"dermal fillers & biostimulators","dermal fillers and biostimulators","liquid bbl",renuva,"full facial balancing","facial balancing",sculptra,radiesse,biostimulator,biostimulators,"poly-l-lactic acid","collagen stimulator"}', 4.50, 2, true, 'approved', '[{"a": "No, most dermal fillers are made of hyaluronic acid which your body naturally breaks down over time. Results typically last 6 to 18 months depending on the specific product and area treated.", "q": "Are dermal fillers permanent?"}, {"a": "Most patients return to normal activities immediately. You may experience mild swelling or bruising for 1-3 days, which can usually be covered with makeup.", "q": "What is the downtime after fillers?"}, {"a": "Yes! Hyaluronic acid fillers can be completely dissolved using an enzyme called hyaluronidase if you are unhappy with the results or experience a complication.", "q": "Can filler be dissolved if I don''t like it?"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.services (id, name, slug, category, is_active, created_at, updated_at, summary, description, price_from, price_unit, treatment_time, results_timeline, results_duration, recovery_time, aliases, hero_rating, hero_review_count, is_published, review_status, faqs) VALUES ('3e34866d-e05c-4cb7-9502-363016f61938', 'Laser Skin Resurfacing', 'laser-skin-resurfacing', 'Laser', true, '2026-06-22 14:49:05.613483+00', '2026-06-24 13:01:15.738854+00', 'Resurfaces and rejuvenates skin with laser energy to smooth texture, tone, and lines.', 'Laser skin resurfacing uses precisely controlled laser energy to remove damaged surface skin and stimulate collagen in the layers beneath. It improves fine lines, sun damage, scarring, and uneven texture, revealing smoother, brighter, more youthful skin over a tailored treatment course.', 750, 'Treatment', '30-60 mins', '1-2 weeks', '1-3 Years', '3-7 days', '{"laser skin resurfacing","laser resurfacing","co2 laser","fractional laser",fraxel,"halo laser","erbium laser","laser peels","laser peel","laser treatments","laser treatment","laser skin treatments","laser skin treatment",nightlase,endolift}', 4.50, 2, true, 'approved', '[{"a": "Most patients describe the sensation as a rubber band snapping against the skin. We use topical numbing cream to minimize any discomfort.", "q": "Does laser skin resurfacing hurt?"}, {"a": "Downtime varies depending on the depth of the treatment. Light resurfacing may require 3-5 days of social downtime, while deeper treatments can take up to 2 weeks.", "q": "How much downtime should I expect?"}, {"a": "Many patients see significant improvement after a single session, though a series of 2-3 treatments may be recommended for optimal results.", "q": "How many sessions will I need?"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.services (id, name, slug, category, is_active, created_at, updated_at, summary, description, price_from, price_unit, treatment_time, results_timeline, results_duration, recovery_time, aliases, hero_rating, hero_review_count, is_published, review_status, faqs) VALUES ('77fad708-78e9-411b-82bc-8d8a0b528460', 'PDO Threads', 'pdo-threads', 'Injectables', true, '2026-06-22 14:49:05.613483+00', '2026-06-24 13:01:16.47251+00', 'Dissolvable sutures that lift loose skin and stimulate new collagen.', 'PDO threads are dissolvable polydioxanone sutures placed beneath the skin to lift and tighten sagging areas while stimulating natural collagen production. This minimally invasive treatment offers an immediate, subtle lift with gradual, long-lasting firming of the face and neck.', 500, 'Area', '45-60 mins', 'Immediately', '12-18 Months', '3-7 days', '{"pdo threads","pdo thread","thread lift","thread lifts",threads,pdo,"pdo thread lift"}', 4.50, 2, true, 'approved', '[{"a": "PDO (Polydioxanone) threads are medical-grade absorbable sutures used to gently lift sagging skin and stimulate collagen production.", "q": "What are PDO threads?"}, {"a": "The threads dissolve naturally over 6-9 months, but the collagen stimulation they create can maintain the lifting effect for 12-18 months.", "q": "How long do PDO threads last?"}, {"a": "You may experience mild swelling, bruising, or soreness for a few days, but most patients resume normal activities within 24-48 hours.", "q": "Is there any downtime after a thread lift?"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.services (id, name, slug, category, is_active, created_at, updated_at, summary, description, price_from, price_unit, treatment_time, results_timeline, results_duration, recovery_time, aliases, hero_rating, hero_review_count, is_published, review_status, faqs) VALUES ('3e6a118b-aed6-43be-8200-27e7f41de7c5', 'RF Skin Tightening', 'rf-skin-tightening', 'Skin', true, '2026-06-24 09:02:19.142227+00', '2026-06-24 13:01:17.199564+00', 'Radiofrequency energy that firms and lifts lax skin without surgery or needles.', 'RF skin tightening uses radiofrequency energy to heat the deeper layers of the skin, contracting existing collagen and stimulating new collagen production. Devices such as Thermage and Exilis gradually firm and lift lax skin on the face, neck, and body with little to no downtime.', 600, 'Treatment', '30-60 mins', '3-6 weeks', '1-2 Years', 'None', '{"rf skin tightening","radiofrequency skin tightening","skin tightening","non-surgical skin tightening","skin firming",thermage,exilis,evoke,evolve,forma,votiva,"everesse skin tightening",everesse,xerf}', 4.50, 2, true, 'approved', '[{"a": "RF energy heats the deep layers of the skin, causing immediate collagen contraction and stimulating the production of new collagen over time.", "q": "How does Radiofrequency (RF) skin tightening work?"}, {"a": "Most patients find the treatment very comfortable, often comparing it to a warm stone massage.", "q": "Does the treatment hurt?"}, {"a": "Some immediate tightening is often visible, but optimal results typically appear 2-3 months after a series of treatments.", "q": "When will I see results?"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.services (id, name, slug, category, is_active, created_at, updated_at, summary, description, price_from, price_unit, treatment_time, results_timeline, results_duration, recovery_time, aliases, hero_rating, hero_review_count, is_published, review_status, faqs) VALUES ('59b16f6c-ef26-4e3b-b006-cd2f05a7d9e9', 'IPL / Photofacial', 'ipl-photofacial', 'Laser', true, '2026-06-24 09:02:19.142227+00', '2026-06-24 13:01:17.677974+00', 'Pulsed light that clears sun spots, redness, and uneven tone for clearer skin.', 'IPL photofacials use broadband intense pulsed light to target pigment and visible blood vessels, fading sun spots, redness, and uneven tone while boosting overall clarity. A series of quick, no-downtime sessions leaves the skin brighter and more even.', 350, 'Session', '20-40 mins', '1-2 weeks', '6-12 Months', 'None', '{ipl,"ipl photofacial",photofacial,"photo facial","intense pulsed light",bbl,"broadband light","forever young bbl",photorejuvenation}', NULL, 0, true, 'approved', '[{"a": "Intense Pulsed Light (IPL) effectively treats sun damage, age spots, freckles, rosacea, and broken capillaries.", "q": "What does IPL treat?"}, {"a": "Pigmented spots will darken (sometimes looking like coffee grounds) and naturally flake off over 1-2 weeks.", "q": "What happens to the dark spots after treatment?"}, {"a": "Yes, you can apply makeup immediately after the treatment, though you must be diligent about applying sunscreen.", "q": "Can I wear makeup after an IPL treatment?"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.concerns (id, name, slug, overview, details, faqs, meta_title, meta_description, schema_markup, data_source, source_url, is_published, is_active, created_at, updated_at, aliases) VALUES ('86721a3e-dc92-49b6-bab6-0e02ea3712b8', 'Wrinkles & Fine Lines', 'fine-lines-wrinkles', 'Fine lines and wrinkles are among the most common visible signs of aging. They form from repeated facial movement and the natural loss of collagen and elastin over time. A range of injectable, energy-based, and resurfacing treatments can soften their appearance while preserving natural expression.', '{"signs": "Forehead lines, crow''s feet, smile lines, and fine creases caused by repeated facial movement and natural collagen loss.", "causes": "Aging, sun exposure, genetics, and reduced collagen production all contribute to the development of fine lines and wrinkles.", "results": "Smoother, younger-looking skin with treatments designed to reduce wrinkles while preserving natural facial expressions.", "benefits": "Treatments that support natural collagen production improve firmness, elasticity, and long-term skin health.", "candidate": "Adults looking to soften visible signs of aging, prevent deeper wrinkles, or maintain a refreshed, natural appearance.", "prevention": "Daily SPF, medical-grade skincare, and maintenance treatments help slow visible signs of aging over time.", "injectables": "Botox and dermal fillers soften dynamic wrinkles and restore youthful balance; microneedling, RF tightening, and laser resurfacing rebuild collagen.", "treatment_areas": "Forehead, frown lines, crow''s feet, lip lines, cheeks, and the neck."}', '[{"a": "There is no ''right'' age. Many patients start preventative treatments in their late 20s or early 30s when lines first begin to linger when the face is at rest.", "q": "At what age should I start treating fine lines?"}, {"a": "Botox relaxes the muscles that cause ''dynamic'' wrinkles (like frowning), while fillers restore volume to plump out ''static'' wrinkles and folds (like smile lines).", "q": "What''s the difference between Botox and filler for wrinkles?"}, {"a": "While medical-grade skincare (especially retinoids and Vitamin C) can improve skin texture and soften early fine lines, they cannot eliminate deeper wrinkles caused by muscle movement or volume loss.", "q": "Can skincare products eliminate wrinkles?"}]', NULL, NULL, NULL, 'scraped', NULL, true, true, '2026-06-22 14:49:05.613483+00', '2026-06-24 10:20:27.24747+00', '{wrinkle,wrinkles,"fine line","fine lines",anti-aging,"anti aging"}') ON CONFLICT DO NOTHING;
INSERT INTO public.concerns (id, name, slug, overview, details, faqs, meta_title, meta_description, schema_markup, data_source, source_url, is_published, is_active, created_at, updated_at, aliases) VALUES ('b9715e49-f29c-4e50-aa63-40046d1c1b19', 'Double Chin', 'double-chin-submental-fullness', 'Submental fullness — the ''double chin'' — can persist despite diet and exercise. Fat-dissolving injections, cryolipolysis, and skin tightening reduce fullness beneath the chin for a more sculpted profile.', '{"signs": "Fullness or a ''double chin'' beneath the jaw, even at a healthy weight.", "causes": "Genetics, aging, and weight changes that lead to stubborn submental fat and laxity.", "results": "A more defined, sculpted jaw and chin profile after a series of treatments.", "benefits": "A slimmer, more contoured profile without surgery.", "candidate": "Adults bothered by fullness under the chin who want a non-surgical contouring option.", "prevention": "Results are long-lasting once the desired contour is achieved.", "injectables": "Kybella (deoxycholic acid) permanently destroys treated fat cells; CoolSculpting freezes it.", "treatment_areas": "The submental area beneath the chin and along the jawline."}', '[{"a": "It depends on the anatomy. Kybella is excellent for targeted, smaller pockets of fat, while CoolSculpting might be preferred for a larger volume of submental fat. Both permanently destroy fat cells.", "q": "Is Kybella better than CoolSculpting for a double chin?"}, {"a": "For patients with good skin elasticity, the skin typically retracts nicely. If skin laxity is also a concern, we may recommend pairing fat reduction with a skin tightening treatment.", "q": "Will I have loose skin after the fat is gone?"}, {"a": "No, these treatments are designed for stubborn pockets of fat that persist despite a healthy lifestyle, so you do not need to lose weight beforehand.", "q": "Do I need to lose weight first?"}]', NULL, NULL, NULL, 'scraped', NULL, true, true, '2026-06-22 14:49:05.613483+00', '2026-06-24 10:20:28.575726+00', '{"double chin","submental fullness","submental fat","chin fat"}') ON CONFLICT DO NOTHING;
INSERT INTO public.concerns (id, name, slug, overview, details, faqs, meta_title, meta_description, schema_markup, data_source, source_url, is_published, is_active, created_at, updated_at, aliases) VALUES ('60dc011c-e458-4676-8965-863ac7d19c2a', 'Hyperpigmentation', 'hyperpigmentation', 'Hyperpigmentation is the darkening of patches of skin caused by excess melanin. Chemical peels, IPL photofacials, and laser resurfacing break up pigment and renew the surface to restore a brighter, more even complexion.', '{"signs": "Patches of darker skin, uneven tone, blotchiness, and lingering marks after inflammation or sun exposure.", "causes": "Excess melanin production triggered by UV exposure, inflammation, hormones, or skin injury.", "results": "Brighter, more even skin tone after a tailored series of resurfacing and light-based treatments.", "benefits": "A clearer, more radiant complexion and improved overall skin health.", "candidate": "Adults with uneven pigmentation or discoloration seeking a clearer, more even-toned complexion.", "prevention": "Daily SPF and antioxidant skincare prevent recurrence and protect treatment results.", "injectables": "Pigment concerns are treated with light-based and resurfacing treatments rather than injectables.", "treatment_areas": "Face, neck, chest, hands, and other sun-exposed areas."}', NULL, NULL, NULL, NULL, 'curated', NULL, true, true, '2026-06-24 09:02:19.142227+00', '2026-06-24 09:02:19.142227+00', '{hyperpigmentation,"uneven skin tone",discoloration,"post-inflammatory hyperpigmentation"}') ON CONFLICT DO NOTHING;
INSERT INTO public.concerns (id, name, slug, overview, details, faqs, meta_title, meta_description, schema_markup, data_source, source_url, is_published, is_active, created_at, updated_at, aliases) VALUES ('8ab63fa4-92bc-4f1e-ab02-3bd3e62e93a9', 'Rosacea', 'rosacea', 'Rosacea causes persistent facial redness, flushing, and visible blood vessels. IPL and laser treatments target the dilated vessels behind the redness to calm the complexion and even out tone.', '{"signs": "Persistent redness across the cheeks and nose, flushing, visible capillaries, and sometimes bumps.", "causes": "A combination of genetics, vascular sensitivity, and triggers such as heat, sun, alcohol, and stress.", "results": "Reduced redness and fewer visible vessels after a series of light-based treatments.", "benefits": "A calmer, more even-toned complexion and reduced visible flushing.", "candidate": "Adults with facial redness or visible vessels who want a calmer, more even complexion.", "prevention": "Identifying triggers, daily SPF, and gentle skincare help maintain results.", "injectables": "Rosacea is treated with light and laser therapy rather than injectables.", "treatment_areas": "Cheeks, nose, chin, and central face."}', NULL, NULL, NULL, NULL, 'curated', NULL, true, true, '2026-06-24 09:02:19.142227+00', '2026-06-24 09:02:19.142227+00', '{rosacea,"facial redness",flushing,"broken capillaries"}') ON CONFLICT DO NOTHING;
INSERT INTO public.concerns (id, name, slug, overview, details, faqs, meta_title, meta_description, schema_markup, data_source, source_url, is_published, is_active, created_at, updated_at, aliases) VALUES ('c0ef6d55-dfc7-4ead-b962-3d8214bf94dd', 'Stretch Marks', 'stretch-marks', 'Stretch marks are scars that form when skin stretches rapidly. Microneedling, laser resurfacing, and radiofrequency treatments remodel collagen to soften their texture and blend them with surrounding skin.', '{"signs": "Streaked lines on the skin that may appear red, purple, or silvery-white over time.", "causes": "Rapid stretching of the skin from growth, pregnancy, or weight changes that breaks down collagen and elastin.", "results": "Softer, less noticeable marks and improved texture after a series of treatments.", "benefits": "Smoother, more even skin texture and reduced visibility of marks.", "candidate": "Adults bothered by stretch marks who want to improve their texture and appearance.", "prevention": "Maintaining stable weight and skin hydration helps limit new stretch marks.", "injectables": "Stretch marks are treated with resurfacing and collagen-stimulating treatments rather than injectables.", "treatment_areas": "Abdomen, hips, thighs, breasts, arms, and other areas with stretch marks."}', NULL, NULL, NULL, NULL, 'curated', NULL, true, true, '2026-06-24 09:02:19.142227+00', '2026-06-24 09:02:19.142227+00', '{"stretch marks",striae,"stretch mark"}') ON CONFLICT DO NOTHING;
INSERT INTO public.concerns (id, name, slug, overview, details, faqs, meta_title, meta_description, schema_markup, data_source, source_url, is_published, is_active, created_at, updated_at, aliases) VALUES ('d30d4123-fbbb-4862-acbb-6e12347c2710', 'Dark Spots & Melasma', 'dark-spots-melasma', 'Dark spots and melasma are stubborn forms of pigmentation that can be triggered by sun and hormones. Carefully selected chemical peels, IPL, and laser treatments lighten the discoloration and even out skin tone.', '{"signs": "Brown or gray-brown patches, age spots, and symmetric facial discoloration that worsens with sun.", "causes": "Excess melanin driven by sun exposure, hormonal changes (including pregnancy and birth control), and inflammation.", "results": "Lightened pigmentation and a more even tone after a carefully tailored treatment series.", "benefits": "A brighter, more even complexion with reduced discoloration.", "candidate": "Adults with melasma, age spots, or persistent discoloration seeking a more even complexion.", "prevention": "Strict daily SPF and pigment-focused skincare are essential to prevent recurrence.", "injectables": "Pigment is treated with resurfacing, peels, and light-based treatments rather than injectables.", "treatment_areas": "Cheeks, forehead, upper lip, and other areas of facial pigmentation."}', NULL, NULL, NULL, NULL, 'curated', NULL, true, true, '2026-06-24 09:02:19.142227+00', '2026-06-24 09:02:19.142227+00', '{"dark spots",melasma,"age spots","brown spots",pigment}') ON CONFLICT DO NOTHING;
INSERT INTO public.concerns (id, name, slug, overview, details, faqs, meta_title, meta_description, schema_markup, data_source, source_url, is_published, is_active, created_at, updated_at, aliases) VALUES ('f47b94ca-f82f-4d7c-8c01-47d7a7c8debe', 'Stubborn Body Fat', 'stubborn-body-fat', 'Stubborn pockets of fat can resist even consistent diet and exercise. Non-surgical body contouring and fat-reduction treatments such as CoolSculpting and EmSculpt reduce fat and refine the body''s shape without downtime.', '{"signs": "Localized fat on the abdomen, flanks, thighs, arms, or under the chin that won''t budge with diet and exercise.", "causes": "Genetics and hormones determine where the body stores stubborn fat that resists lifestyle changes.", "results": "A more contoured, refined shape after a series of treatments, with gradual fat reduction over weeks.", "benefits": "Reduced stubborn fat and improved contour without surgery or downtime.", "candidate": "Adults near their goal weight who want to reduce specific pockets of stubborn fat.", "prevention": "Results are long-lasting when paired with a stable, healthy lifestyle.", "injectables": "Kybella dissolves small fat pockets; CoolSculpting and body contouring address larger areas non-surgically.", "treatment_areas": "Abdomen, flanks, thighs, arms, back, and under the chin."}', NULL, NULL, NULL, NULL, 'curated', NULL, true, true, '2026-06-24 09:02:19.142227+00', '2026-06-24 09:02:19.142227+00', '{"stubborn fat","body fat","unwanted fat","fat reduction",contouring}') ON CONFLICT DO NOTHING;
INSERT INTO public.concerns (id, name, slug, overview, details, faqs, meta_title, meta_description, schema_markup, data_source, source_url, is_published, is_active, created_at, updated_at, aliases) VALUES ('38fc4881-2467-4fc0-a2e0-01f1a606f6cc', 'Acne Scars', 'acne-scars', 'Acne scars are the textural marks left behind after breakouts heal. Resurfacing treatments, microneedling, and chemical peels remodel the skin''s surface and stimulate collagen to smooth pitted scarring and restore a more even texture.', '{"signs": "Pitted or depressed scars, raised scars, post-inflammatory marks, and uneven, textured skin from past breakouts.", "causes": "Deeper inflammation from acne that damages collagen, leading to indentations or raised tissue as the skin heals.", "results": "Visibly smoother texture and softened scarring after a series of resurfacing or microneedling treatments.", "benefits": "Refined texture, reduced scar depth, and renewed confidence in clearer skin.", "candidate": "Teens and adults with residual acne scarring or uneven texture who want smoother, clearer skin.", "prevention": "Treating active acne early and maintaining a medical-grade skincare routine help limit future scarring.", "injectables": "Treatment is primarily resurfacing-based; microneedling and chemical peels are common first-line options.", "treatment_areas": "Face, back, chest, and other areas affected by past acne."}', '[{"a": "While completely erasing them is difficult, modern treatments like microneedling and laser resurfacing can dramatically reduce their depth and visibility to the point where they are barely noticeable.", "q": "Are acne scars permanent?"}, {"a": "Acne scars are typically ''atrophic'' (indented, like ice pick or boxcar scars) or ''hypertrophic'' (raised). A consultation is needed to determine the type and best treatment protocol.", "q": "How do I know what kind of acne scars I have?"}, {"a": "Always treat active acne first. Performing scar treatments on actively inflamed skin can worsen the acne and create new scars.", "q": "Should I treat active acne or scars first?"}]', NULL, NULL, NULL, 'curated', NULL, true, true, '2026-06-24 09:02:19.142227+00', '2026-06-24 10:20:27.557669+00', '{"acne scar","acne scars",scarring,"pitted scars","textured skin"}') ON CONFLICT DO NOTHING;
INSERT INTO public.concerns (id, name, slug, overview, details, faqs, meta_title, meta_description, schema_markup, data_source, source_url, is_published, is_active, created_at, updated_at, aliases) VALUES ('e99d687d-fcbd-42a5-8025-6b0678239587', 'Sun Damage', 'sun-damage', 'Years of sun exposure leave rough texture, dullness, and visible spots. IPL photofacials, chemical peels, and laser resurfacing fade sun-induced damage and renew the skin for a brighter, healthier complexion.', '{"signs": "Sun spots, rough or leathery texture, uneven tone, freckling, and overall dullness.", "causes": "Cumulative UV exposure that damages collagen and stimulates excess melanin.", "results": "Clearer, more even, and visibly refreshed skin after a tailored series of treatments.", "benefits": "A brighter, healthier-looking complexion and improved skin quality.", "candidate": "Adults with sun spots or weathered, uneven skin seeking a brighter, smoother complexion.", "prevention": "Daily SPF and antioxidant skincare prevent further damage and protect results.", "injectables": "Sun damage is treated with light-based and resurfacing treatments rather than injectables.", "treatment_areas": "Face, neck, chest, hands, and other sun-exposed areas."}', '[{"a": "While we can''t reverse cellular DNA damage, we can significantly reverse the visible signs of sun damage (brown spots, redness, and rough texture) using lasers, IPL, and chemical peels.", "q": "Can sun damage be reversed?"}, {"a": "They can if you don''t protect your skin. Daily broad-spectrum SPF 30+ and antioxidant serums are required to maintain your treatment results.", "q": "Will the brown spots come back?"}, {"a": "Fall and winter are generally the best times for laser or peel treatments, as you will need to avoid sun exposure while your skin heals.", "q": "What is the best time of year to treat sun damage?"}]', NULL, NULL, NULL, 'curated', NULL, true, true, '2026-06-24 09:02:19.142227+00', '2026-06-24 10:20:27.868613+00', '{"sun damage","sun spots",photodamage,"sun-damaged skin"}') ON CONFLICT DO NOTHING;
INSERT INTO public.concerns (id, name, slug, overview, details, faqs, meta_title, meta_description, schema_markup, data_source, source_url, is_published, is_active, created_at, updated_at, aliases) VALUES ('0eef1b52-1173-4024-99f2-2de9c6daa114', 'Loose & Sagging Skin', 'skin-laxity-sagging', 'Loss of skin firmness leads to sagging along the jawline, neck, and cheeks. Focused ultrasound, radiofrequency tightening, threads, and collagen-stimulating treatments restore a firmer, lifted appearance without surgery.', '{"signs": "Loose skin along the jawline and neck, jowling, and reduced firmness on the face and body.", "causes": "Collagen and elastin decline, aging, weight changes, and gravity.", "results": "Gradual firming and lifting as new collagen forms over the weeks and months following treatment.", "benefits": "A firmer, more contoured, naturally lifted appearance without surgery.", "candidate": "Adults with mild to moderate skin laxity who want non-surgical tightening and lift.", "prevention": "Ongoing collagen-stimulating treatments help maintain firmness over time.", "injectables": "PDO threads provide lift while energy devices such as Ultherapy and RF tighten tissue.", "treatment_areas": "Jawline, neck, cheeks, brows, and body areas with loose skin."}', '[{"a": "Yes, treatments like RF and Ultrasound (Ultherapy) work by heating the deep layers of skin to stimulate your body''s own collagen production, resulting in gradual, natural firming.", "q": "Do non-surgical skin tightening treatments actually work?"}, {"a": "Because these treatments rely on your body generating new collagen, results develop gradually over 2 to 3 months following the procedure.", "q": "How long does it take to see results from skin tightening?"}, {"a": "Results typically last 1 to 2 years. The aging process continues, so maintenance treatments are recommended to keep ahead of natural collagen loss.", "q": "How long do the results last?"}]', NULL, NULL, NULL, 'scraped', NULL, true, true, '2026-06-22 14:49:05.613483+00', '2026-06-24 10:20:28.180444+00', '{laxity,sagging,"loose skin","skin laxity",jowls,tightening}') ON CONFLICT DO NOTHING;
